// ShaderLab Custom — Sphere
uniform vec3  uColor;
uniform float uBright,uEdge;
uniform float uLodFade;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.46)discard;if(0.0>0.005&&d<0.0)discard;alpha=1.0-smoothstep(0.27,0.46,d);}
  col=uColor*(1.59*(0.30+vBlink*0.0));
  col=pow(max(col*vec3(0.63,0.63,0.63),vec3(0.0)),vec3(1.0/1.0));
  {float _gf=exp(-d*8.0)*0.50;col=mix(col,col*2.5,_gf*0.28);}
  alpha=pow(max(alpha,0.0),1.43)*0.15+0.0;
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0)*uLodFade);
}
